// src/pages/Contracts.js
import { useCallback, useEffect, useMemo, useState } from "react";
import api from "../api";

/* ================= Helpers ================= */
const TYPE_MAP = [
    { label: "Thi công", value: "CONSTRUCTION" },
    { label: "Dịch vụ", value: "SERVICE" },
];

const STATUS_MAP = [
    { label: "Chờ duyệt/Ký", value: "PENDING" },
    { label: "Đang thực hiện", value: "ACTIVE" },
    { label: "Hoàn tất", value: "COMPLETED" },
    { label: "Hủy", value: "CANCELLED" },
];

const PAGE_SIZE = 10;

const findLabel = (list, v) => list.find((x) => x.value === v)?.label || v || "-";
const fmtMoney = (n) =>
    (Number.isFinite(n) ? n : Number(n || 0)).toLocaleString("vi-VN", { maximumFractionDigits: 0 });
const parseMoney = (s) => {
    if (typeof s === "number") return s;
    if (!s) return 0;
    const digits = String(s).replace(/[^\d]/g, "");
    return Number(digits || 0);
};

/** Ép về enum hợp lệ cho BE */
const coerceType = (t) => {
    const v = (t || "").toString().trim().toUpperCase();
    return v === "CONSTRUCTION" || v === "SERVICE" ? v : "CONSTRUCTION";
};
const coerceStatus = (s) => {
    const v = (s || "").toString().trim().toUpperCase();
    return ["PENDING", "ACTIVE", "COMPLETED", "CANCELLED"].includes(v) ? v : "ACTIVE";
};

function useDebounce(value, delay = 450) {
    const [v, setV] = useState(value);
    useEffect(() => {
        const t = setTimeout(() => setV(value), delay);
        return () => clearTimeout(t);
    }, [value, delay]);
    return v;
}

function emptyForm() {
    return {
        contractCode: "",
        salesId: null,
        customerId: null,
        title: "",
        totalAmount: 0,
        signedDate: "", // YYYY-MM-DD
        dueDate: "", // YYYY-MM-DD
        contractType: "CONSTRUCTION", // enum
        status: "ACTIVE", // enum
    };
}

/* ================= Page ================= */
export default function Contracts() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // filters
    const [q, setQ] = useState("");
    const dq = useDebounce(q, 450);
    const [type, setType] = useState("");
    const [status, setStatus] = useState("");
    const [fromDate, setFromDate] = useState("");
    const [toDate, setToDate] = useState("");

    // modal
    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState(emptyForm());

    // options
    const [salesOptions, setSalesOptions] = useState([]); // [{id, name}]
    const [customerOptions, setCustomerOptions] = useState([]); // [{id, name}]

    const loadOptions = useCallback(async () => {
        // Sales (user role = SALES/ACCOUNTANT/ADMIN đều có thể phụ trách? Mặc định lấy SALES + ADMIN)
        try {
            const [salesRes, cusRes] = await Promise.all([
                api.get("/api/users", { params: { role: "SALES", status: "ACTIVE", page: 0, size: 1000 } }),
                api.get("/api/customers", { params: { page: 0, size: 1000 } }),
            ]);

            const sales = (Array.isArray(salesRes.data) ? salesRes.data : salesRes.data?.content || []).map((u) => ({
                id: u.id,
                name: u.fullName || u.username,
            }));
            const customers = (Array.isArray(cusRes.data) ? cusRes.data : cusRes.data?.content || []).map((c) => ({
                id: c.id,
                name: c.name || c.customerName,
            }));

            setSalesOptions(sales);
            setCustomerOptions(customers);
        } catch {
            // ignore
        }
    }, []);

    const load = useCallback(async () => {
        setLoading(true);
        try {
            const { data } = await api.get("/api/contracts", {
                params: {
                    q: dq || undefined,
                    type: type || undefined, // must be enum
                    status: status || undefined, // must be enum
                    from: fromDate || undefined,
                    to: toDate || undefined,
                    page,
                    size: PAGE_SIZE,
                    sort: "id,desc",
                },
            });

            const list = Array.isArray(data) ? data : data?.content || [];
            setTotalPages(typeof data?.totalPages === "number" ? data.totalPages : 1);

            setRows(
                list.map((c) => ({
                    id: c.id,
                    contractCode: c.contractCode,
                    title: c.title,
                    totalAmount: c.totalAmount || 0,
                    remainingAmount: c.remainingAmount ?? c.remainAmount ?? 0,
                    signedDate: c.signedDate,
                    dueDate: c.dueDate,
                    contractType: coerceType(c.contractType),
                    status: coerceStatus(c.status),
                    salesName: c.salesName || c.sales?.fullName || "",
                    customerName: c.customerName || c.customer?.name || "",
                    salesId: c.sales?.id ?? c.salesId ?? null,
                    customerId: c.customer?.id ?? c.customerId ?? null,
                }))
            );
        } finally {
            setLoading(false);
        }
    }, [dq, type, status, fromDate, toDate, page]);

    useEffect(() => {
        load();
    }, [load]);

    useEffect(() => {
        loadOptions();
    }, [loadOptions]);

    /* ============ CRUD ============ */
    const openCreate = () => {
        setEditing(null);
        setForm(emptyForm());
        setShow(true);
    };

    const openEdit = (row) => {
        setEditing(row);
        setForm({
            contractCode: row.contractCode || "",
            salesId: row.salesId || null,
            customerId: row.customerId || null,
            title: row.title || "",
            totalAmount: row.totalAmount || 0,
            signedDate: row.signedDate || "",
            dueDate: row.dueDate || "",
            contractType: coerceType(row.contractType),
            status: coerceStatus(row.status),
        });
        setShow(true);
    };

    const payloadFromForm = () => ({
        contractCode: form.contractCode?.trim() || undefined,
        salesId: form.salesId,
        customerId: form.customerId,
        title: form.title?.trim() || "",
        totalAmount: parseMoney(form.totalAmount),
        signedDate: form.signedDate || null,
        dueDate: form.dueDate || null,
        contractType: coerceType(form.contractType), // <-- enum chuẩn
        status: coerceStatus(form.status), // <-- enum chuẩn
    });

    async function save(e) {
        e.preventDefault();
        try {
            const payload = payloadFromForm();
            if (!editing) {
                await api.post("/api/contracts", payload);
                alert("Đã tạo hợp đồng");
            } else {
                await api.put(`/api/contracts/${editing.id}`, payload);
                alert("Đã cập nhật hợp đồng");
            }
            setShow(false);
            await load();
        } catch (err) {
            alert(err?.response?.data?.error || "Lưu hợp đồng thất bại");
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá hợp đồng ${row.contractCode}?`)) return;
        try {
            await api.delete(`/api/contracts/${row.id}`);
            await load();
            alert("Đã xoá hợp đồng");
        } catch (err) {
            alert(err?.response?.data?.error || "Xoá hợp đồng thất bại");
        }
    }

    /* derived */
    const typeOptions = useMemo(() => [{ label: "Tất cả", value: "" }, ...TYPE_MAP], []);
    const statusOptions = useMemo(() => [{ label: "Tất cả", value: "" }, ...STATUS_MAP], []);

    return (
        <div className="space-y-4">
            {/* Filters */}
            <div className="flex flex-col gap-3 md:flex-row md:items-end md:justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Hợp đồng</h2>
                    <p className="text-sm text-slate-500">Tìm kiếm, thêm mới và quản lý hợp đồng</p>
                </div>

                <div className="flex flex-wrap items-end gap-2">
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                        <input
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow w-64"
                            placeholder="Mã/tiêu đề/KH/NVKD…"
                            value={q}
                            onChange={(e) => {
                                setQ(e.target.value);
                                setPage(0);
                            }}
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Loại HĐ</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={type}
                            onChange={(e) => {
                                setType(coerceType(e.target.value) || "");
                                setPage(0);
                            }}
                        >
                            {typeOptions.map((t) => (
                                <option key={t.value || "ALL"} value={t.value}>
                                    {t.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Trạng thái</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={status}
                            onChange={(e) => {
                                const v = e.target.value;
                                setStatus(v ? coerceStatus(v) : "");
                                setPage(0);
                            }}
                        >
                            {statusOptions.map((s) => (
                                <option key={s.value || "ALL"} value={s.value}>
                                    {s.label}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Từ ngày</label>
                        <input
                            type="date"
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={fromDate}
                            onChange={(e) => {
                                setFromDate(e.target.value);
                                setPage(0);
                            }}
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Đến ngày</label>
                        <input
                            type="date"
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={toDate}
                            onChange={(e) => {
                                setToDate(e.target.value);
                                setPage(0);
                            }}
                        />
                    </div>

                    <button onClick={openCreate} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 ml-auto">
                        Thêm hợp đồng
                    </button>
                </div>
            </div>

            {/* Table */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Mã HĐ</th>
                            <th className="px-4 py-3 text-left">Tiêu đề</th>
                            <th className="px-4 py-3 text-left">Khách hàng</th>
                            <th className="px-4 py-3 text-left">Sale</th>
                            <th className="px-4 py-3 text-left">Loại</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-right">Giá trị</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={8}>
                                    Đang tải…
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={8}>
                                    Chưa có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((c) => (
                                <tr key={c.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{c.contractCode}</td>
                                    <td className="px-4 py-3">{c.title || "-"}</td>
                                    <td className="px-4 py-3">{c.customerName || "-"}</td>
                                    <td className="px-4 py-3">{c.salesName || "-"}</td>
                                    <td className="px-4 py-3">{findLabel(TYPE_MAP, c.contractType)}</td>
                                    <td className="px-4 py-3">
                      <span
                          className={
                              "px-2 py-0.5 rounded-full text-xs " +
                              (c.status === "COMPLETED"
                                  ? "bg-emerald-100 text-emerald-700"
                                  : c.status === "CANCELLED"
                                      ? "bg-rose-100 text-rose-700"
                                      : c.status === "PENDING"
                                          ? "bg-amber-100 text-amber-700"
                                          : "bg-sky-100 text-sky-700")
                          }
                      >
                        {findLabel(STATUS_MAP, c.status)}
                      </span>
                                    </td>
                                    <td className="px-4 py-3 text-right">{fmtMoney(c.totalAmount)} đ</td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="inline-flex gap-2">
                                            <button
                                                onClick={() => openEdit(c)}
                                                className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                            >
                                                Sửa
                                            </button>
                                            <button
                                                onClick={() => remove(c)}
                                                className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                            >
                                                Xoá
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2 justify-center">
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="px-3 py-1.5 text-sm">
                    Trang {page + 1}/{totalPages}
                </div>
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => p + 1)}
                    disabled={page + 1 >= totalPages}
                >
                    Sau →
                </button>
            </div>

            {/* Modal Thêm/Sửa hợp đồng */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl max-h-[90vh] bg-white rounded-2xl shadow-xl border border-indigo-100 flex flex-col">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing ? "Sửa hợp đồng" : "Thêm hợp đồng"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>
                                Đóng
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-5">
                            <form id="contractForm" onSubmit={save} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm text-slate-600">Mã hợp đồng</label>
                                    <input
                                        value={form.contractCode}
                                        onChange={(e) => setForm((f) => ({ ...f, contractCode: e.target.value }))}
                                        placeholder="VD: HD-20240911-8304"
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    />
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Khách hàng</label>
                                    <select
                                        value={form.customerId ?? ""}
                                        onChange={(e) => setForm((f) => ({ ...f, customerId: e.target.value ? Number(e.target.value) : null }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                        required
                                    >
                                        <option value="">-- Chọn khách hàng --</option>
                                        {customerOptions.map((c) => (
                                            <option key={c.id} value={c.id}>
                                                {c.name}
                                            </option>
                                        ))}
                                    </select>
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Phụ trách (Sale)</label>
                                    <select
                                        value={form.salesId ?? ""}
                                        onChange={(e) => setForm((f) => ({ ...f, salesId: e.target.value ? Number(e.target.value) : null }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                        required
                                    >
                                        <option value="">-- Chọn NVKD --</option>
                                        {salesOptions.map((s) => (
                                            <option key={s.id} value={s.id}>
                                                {s.name}
                                            </option>
                                        ))}
                                    </select>
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Tiêu đề</label>
                                    <input
                                        value={form.title}
                                        onChange={(e) => setForm((f) => ({ ...f, title: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                        placeholder="VD: Thi công phần thô nhà A"
                                    />
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Giá trị (đ)</label>
                                    <input
                                        value={form.totalAmount ? fmtMoney(form.totalAmount) : ""}
                                        onChange={(e) =>
                                            setForm((f) => ({
                                                ...f,
                                                totalAmount: parseMoney(e.target.value),
                                            }))
                                        }
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                        inputMode="numeric"
                                        placeholder="VD: 3.000.000.000"
                                    />
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Ngày ký</label>
                                    <input
                                        type="date"
                                        value={form.signedDate || ""}
                                        onChange={(e) => setForm((f) => ({ ...f, signedDate: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    />
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Ngày hết hạn</label>
                                    <input
                                        type="date"
                                        value={form.dueDate || ""}
                                        onChange={(e) => setForm((f) => ({ ...f, dueDate: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    />
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Loại hợp đồng</label>
                                    <select
                                        value={form.contractType}
                                        onChange={(e) => setForm((f) => ({ ...f, contractType: coerceType(e.target.value) }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    >
                                        {TYPE_MAP.map((t) => (
                                            <option key={t.value} value={t.value}>
                                                {t.label}
                                            </option>
                                        ))}
                                    </select>
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Trạng thái</label>
                                    <select
                                        value={form.status}
                                        onChange={(e) => setForm((f) => ({ ...f, status: coerceStatus(e.target.value) }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    >
                                        {STATUS_MAP.map((s) => (
                                            <option key={s.value} value={s.value}>
                                                {s.label}
                                            </option>
                                        ))}
                                    </select>
                                </div>
                            </form>
                        </div>

                        <div className="p-4 border-t flex justify-end gap-2">
                            <button
                                type="button"
                                className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                onClick={() => setShow(false)}
                            >
                                Huỷ
                            </button>
                            <button form="contractForm" className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                Lưu
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
